  `id` varchar(50) NOT NULL,
  `company_id` int(11) DEFAULT 1,
  `role_id` int(11) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `email` varchar(255) DEFAULT NULL,
  `sector` varchar(255) DEFAULT NULL,
  `unit_id` varchar(50) DEFAULT NULL,
  `role` enum('Administrador','Respons├ível de Setor','Colaborador','Coordenador','Setor de Compras','Suporte T├®cnico','Volunt├írio') DEFAULT 'Colaborador',
  `status` enum('Ativo','Inativo') DEFAULT 'Ativo',
  `avatar_url` text DEFAULT NULL,
  `phone` varchar(50) DEFAULT NULL,
  `login_name` varchar(100) NOT NULL,
  `password` varchar(255) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `gender` varchar(20) DEFAULT '',
  `position` varchar(100) DEFAULT '',
  `last_activity` timestamp NULL DEFAULT NULL,
  `access_number` varchar(100) DEFAULT '',
  `address_street` varchar(255) DEFAULT '',
  `address_number` varchar(30) DEFAULT '',
  `address_complement` varchar(100) DEFAULT '',
  `address_neighborhood` varchar(100) DEFAULT '',
  `address_city` varchar(100) DEFAULT '',
  `address_state` varchar(50) DEFAULT '',
  `address_zip` varchar(20) DEFAULT '',
  PRIMARY KEY (`id`),
  UNIQUE KEY `login_name` (`login_name`),
  UNIQUE KEY `email` (`email`),
  KEY `unit_id` (`unit_id`),
  KEY `idx_role` (`role_id`),
  KEY `idx_company` (`company_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

